/**
 * 字→注音查找表 & 注音分類常數
 */
import { ALL_CHARS } from './gameEngine';

// ─── 字→注音查找表 ──────────────────────────────────────────────
export const CHAR_ZHUYIN_MAP = {};
ALL_CHARS.forEach(c => { CHAR_ZHUYIN_MAP[c.char] = c.zhuyin; });

// ─── 注音符號分類 ────────────────────────────────────────────────
export const TONE_MARKS = new Set(['ˊ', 'ˇ', 'ˋ', '˙']);

export function parseZhuyin(zy) {
  const symbols = [];
  let tone = '';
  for (const ch of zy) {
    if (TONE_MARKS.has(ch)) {
      tone = ch;
    } else {
      symbols.push(ch);
    }
  }
  return { symbols, tone };
}
